import React, { useState, useEffect, useRef } from "react";
import { PRIORITIES, STATUSES } from "../utils/costants";

const EMPTY = { title: "", description: "", priority: "Medium", status: "Open" };

export default function FeatureModal({ feature, onSave, onClose }) {
  const [form, setForm] = useState(feature ? { ...feature } : { ...EMPTY });
  const [imageFile, setImageFile] = useState(null);
  const [errors, setErrors] = useState({});
  const titleRef = useRef(null);

  const isEdit = Boolean(feature);

  useEffect(() => {
    titleRef.current?.focus();
  }, []);

  // Close on Escape
  useEffect(() => {
    const handler = (e) => { if (e.key === "Escape") onClose(); };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [onClose]);

  function validate() {
    const errs = {};
    if (!form.title.trim()) errs.title = "Title is required.";
    else if (form.title.trim().length < 3) errs.title = "Title must be at least 3 characters.";
    if (!form.description.trim()) errs.description = "Description is required.";
    return errs;
  }


  function handleChange(e) {
    const { name, value, type, files } = e.target;
    if (type === "file") {
      setImageFile(files[0]);
    } else {
      setForm((f) => ({ ...f, [name]: value }));
      if (errors[name]) setErrors((er) => ({ ...er, [name]: undefined }));
    }
  }

  function handleSubmit(e) {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) { setErrors(errs); return; }
    // Pass image file if present
    onSave(imageFile ? { ...form, image: imageFile } : form);
    onClose();
  }

  return (
    <div className="modal-backdrop" onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div className="modal" role="dialog" aria-modal="true" aria-label={isEdit ? "Edit Feature" : "New Feature"}>
        <div className="modal-header">
          <h2 className="modal-title">{isEdit ? "Edit Request" : "New Request"}</h2>
          <button className="btn-icon" onClick={onClose} aria-label="Close">715</button>
        </div>

        <form onSubmit={handleSubmit} noValidate>
          <div className="field">
            <label htmlFor="title">Title</label>
            <input
              ref={titleRef}
              id="title"
              name="title"
              type="text"
              value={form.title}
              onChange={handleChange}
              className={errors.title ? "input-error" : ""}
              required
              minLength={3}
            />
            {errors.title && <div className="error-msg">{errors.title}</div>}
          </div>

          <div className="field">
            <label htmlFor="description">Description</label>
            <textarea
              id="description"
              name="description"
              value={form.description}
              onChange={handleChange}
              className={errors.description ? "input-error" : ""}
              required
              rows={3}
            />
            {errors.description && <div className="error-msg">{errors.description}</div>}
          </div>

          <div className="field-row">
            <div className="field">
              <label htmlFor="priority">Priority</label>
              <select
                id="priority"
                name="priority"
                value={form.priority}
                onChange={handleChange}
              >
                {PRIORITIES.map((p) => (
                  <option key={p} value={p}>{p}</option>
                ))}
              </select>
            </div>
            <div className="field">
              <label htmlFor="status">Status</label>
              <select
                id="status"
                name="status"
                value={form.status}
                onChange={handleChange}
              >
                {STATUSES.map((s) => (
                  <option key={s} value={s}>{s}</option>
                ))}
              </select>
            </div>
          </div>

          <div className="field">
            <label htmlFor="image">Image (optional)</label>
            <input
              id="image"
              name="image"
              type="file"
              accept="image/*"
              onChange={handleChange}
            />
          </div>

          <div className="modal-footer">
            <button className="btn btn-ghost" type="button" onClick={onClose}>Cancel</button>
            <button className="btn btn-primary" type="submit">{isEdit ? "Save" : "Add"}</button>
          </div>
        </form>
      </div>
    </div>
  );
}
